{"code":"from hermes_tools import terminal, read_file
import json, os, glob, re
base=os.path.expanduser('~/.zeroclaw/workspace/company-wiki')
# list run manifests
manifests=sorted(glob.glob(os.path.join(base,'raw/run-manifests/*.json')))
latest=manifests[-1]
prev=manifests[-2] if len(manifests)>=2 else None
with open(latest) as f: latest_j=json.load(f)
prev_j=None
if prev:
    with open(prev) as f: prev_j=json.load(f)
# index first lines
idx=read_file(os.path.join(base,'index.md'), offset=1, limit=40)['content']
# required files excerpts
files=[
'concepts/slack-history-capture-overview.md',
'concepts/notion-workspace-overview.md',
'concepts/github-org-overview-orbisoptimus.md',
'concepts/trello-company-portfolio-overview.md',
'entities/notion-data-source-action-items.md',
'entities/notion-data-source-todo.md',
'entities/notion-data-source-sentry-issue.md',
'entities/notion-data-source-slow-api.md',
'entities/notion-data-source-prd.md',
'entities/notion-data-source-untitled.md',
'entities/trello-board-6699f5adf7a7e4d6d006821f.md',
'entities/trello-board-66cc398f1948e5af2a76f548.md',
]
excerpts={}
for rel in files:
    path=os.path.join(base,rel)
    try:
        excerpts[rel]=read_file(path, offset=1, limit=120)['content']
    except Exception as e:
        excerpts[rel]=f'ERROR: {e}'
# load source manifests referenced by top-level latest/prev
source_details={}
for label in ['slack','trello','github','notion']:
    src=latest_j['sources'].get(label,{})
    man=src.get('manifest')
    det={}
    if man and os.path.exists(man):
        with open(man) as f: det['latest']=json.load(f)
    if prev_j:
        pman=prev_j['sources'].get(label,{}).get('manifest')
        if pman and os.path.exists(pman):
            with open(pman) as f: det['prev']=json.load(f)
    source_details[label]=det
# GitHub repo list payloads from latest/prev manifest raw items if possible
repo_diffs=[]
for key in ['latest','prev']:
    pass

def find_repo_items(man):
    items=[]
    if not man: return items
    for k,v in man.items():
        if isinstance(v,list):
            for x in v:
                if isinstance(x,dict) and x.get('kind')=='repo_list' and x.get('path'):
                    items.append(x['path'])
        elif isinstance(v,dict):
            for a,b in v.items():
                if isinstance(b,list):
                    for x in b:
                        if isinstance(x,dict) and x.get('kind')=='repo_list' and x.get('path'):
                            items.append(x['path'])
    return items
latest_g=source_details['github'].get('latest')
prev_g=source_details['github'].get('prev')
lg_paths=find_repo_items(latest_g)
pg_paths=find_repo_items(prev_g)
# fallback: any path values ending json in manifest

def recurse_paths(obj, acc):
    if isinstance(obj,dict):
        for k,v in obj.items():
            if k=='path' and isinstance(v,str) and v.endswith('.json'):
                acc.append(v)
            else:
                recurse_paths(v, acc)
    elif isinstance(obj,list):
        for x in obj:
            recurse_paths(x, acc)
latest_paths=[]; prev_paths=[]
recurse_paths(latest_g, latest_paths)
recurse_paths(prev_g, prev_paths)

def load_repos(paths):
    for p in paths:
        if os.path.exists(p):
            try:
                with open(p) as f:
                    j=json.load(f)
                # common shapes
                if isinstance(j,dict):
                    if 'repositories' in j and isinstance(j['repositories'], list):
                        return j['repositories'], p
                    if 'data' in j and isinstance(j['data'], list):
                        return j['data'], p
                    if 'items' in j and isinstance(j['items'], list):
                        return j['items'], p
                elif isinstance(j,list):
                    return j,p
            except Exception:
                pass
    return [], None
latest_repos, latest_repo_path = load_repos(lg_paths+latest_paths)
prev_repos, prev_repo_path = load_repos(pg_paths+prev_paths)
# map repo diff by pushedAt/updatedAt

def repo_map(repos):
    m={}
    for r in repos:
        if not isinstance(r,dict): continue
        name=r.get('name') or r.get('full_name') or r.get('fullName')
        if not name: continue
        m[name]=r
    return m
lm=repo_map(latest_repos); pm=repo_map(prev_repos)
for name in sorted(set(lm)|set(pm)):
    a=lm.get(name,{}); b=pm.get(name,{})
    fields=['pushedAt','updatedAt','stargazerCount','openIssuesCount','forkCount']
    changes={}
    for fld in fields:
        if a.get(fld)!=b.get(fld):
            changes[fld]=[b.get(fld), a.get(fld)]
    if changes:
        repo_diffs.append({'repo':name,'changes':changes})
# Trello board pages/activity extract
board_summ={}
for rel in ['entities/trello-board-6699f5adf7a7e4d6d006821f.md','entities/trello-board-66cc398f1948e5af2a76f548.md']:
    txt=excerpts[rel]
    m1=re.search(r'^title: (.+)$', txt, re.M)
    m2=re.search(r'^last_activity: (.+)$', txt, re.M)
    m3=re.search(r'^open_cards: (.+)$', txt, re.M)
    m4=re.search(r'^open_lists: (.+)$', txt, re.M)
    board_summ[rel]={'title':m1.group(1) if m1 else None,'last_activity':m2.group(1) if m2 else None,'open_cards':m3.group(1) if m3 else None,'open_lists':m4.group(1) if m4 else None}
# Notion entity extracted metadata
notion_meta={}
for rel in files:
    if 'notion-data-source-' in rel:
        txt=excerpts[rel]
        md={}
        for fld in ['title','row_count','last_edited_time_max','fetched_at','updated']:
            m=re.search(rf'^{fld}: (.+)$', txt, re.M)
            if m: md[fld]=m.group(1)
        notion_meta[rel]=md
# Slack overview excerpt parse
slack_txt=excerpts['concepts/slack-history-capture-overview.md']
slack_meta={}
for fld in ['updated','channel_count','history_channel_count','history_message_count_total','history_latest_message_ts_max']:
    m=re.search(rf'^{fld}: (.+)$', slack_txt, re.M)
    if m: slack_meta[fld]=m.group(1)
# Slack latest/prev manifest compare basic
slack_compare={}
for which in ['latest','prev']:
    man=source_details['slack'].get(which)
    if man:
        slack_compare[which]={k:man.get(k) for k in ['generated_at','created_count','deduped_count','history_ok_count','history_error_count'] if k in man}
        chs=[]
        for c in man.get('history_channels',[])[:20]:
            chs.append({k:c.get(k) for k in ['channel_id','channel_name','message_count','latest_message_ts']})
        slack_compare[which]['channels']=chs
# Notion manifest summary
notion_compare={}
for which in ['latest','prev']:
    man=source_details['notion'].get(which)
    if man:
        notion_compare[which]={k:man.get(k) for k in ['generated_at','created_count','deduped_count','page_count','data_source_count'] if k in man}
# Trello manifest summary
tr_compare={}
for which in ['latest','prev']:
    man=source_details['trello'].get(which)
    if man:
        tr_compare[which]={k:man.get(k) for k in ['generated_at','created_count','deduped_count'] if k in man}
# Github manifest summary
gh_compare={}
for which in ['latest','prev']:
    man=source_details['github'].get(which)
    if man:
        gh_compare[which]={k:man.get(k) for k in ['generated_at','created_count','deduped_count'] if k in man}
print(json.dumps({
  'latest_manifest': latest,
  'prev_manifest': prev,
  'latest_generated_at': latest_j.get('generated_at'),
  'prev_generated_at': prev_j.get('generated_at') if prev_j else None,
  'build': latest_j.get('build'),
  'index_head': idx,
  'slack_meta': slack_meta,
  'slack_compare': slack_compare,
  'notion_compare': notion_compare,
  'trello_compare': tr_compare,
  'github_compare': gh_compare,
  'repo_list_paths': {'latest': latest_repo_path, 'prev': prev_repo_path},
  'repo_diffs': repo_diffs[:20],
  'board_summ': board_summ,
  'notion_meta': notion_meta,
  'excerpts': excerpts,
}, ensure_ascii=False, indent=2))"}

