                if isinstance(pv,dict) and pv.get('type')=='title':
                    arr=pv.get('title',[])
                    title=''.join([x.get('plain_text','') for x in arr if isinstance(x,dict)])
                    break
            if title:
                titles.append(title)
        for r in rows:
            if isinstance(r,dict):
                t=r.get('last_edited_time')
                if t and (max_edit is None or t>max_edit):
                    max_edit=t
        matches.append({
            'path':path,
            'first_seen_at':j.get('first_seen_at'),
            'last_seen_at':j.get('last_seen_at'),
            'generated_at':payload.get('generated_at') or payload.get('fetched_at'),
            'row_count':len(rows),
            'max_row_last_edited_time':max_edit,
            'sample_titles':titles,
        })
    matches.sort(key=lambda x:(x['last_seen_at'] or '', x['generated_at'] or ''))
    summary[name]=matches[-3:]
